const thL = (s) => `padding:8px 12px;text-align:left;color:#888;font-weight:700;border-bottom:2px solid #333;${s||""}`;

const q14Html = `<table style="${tbl()}"><thead><tr><th style="${thL()}"></th><th style="${th()}">Execution 1</th><th style="${th()}">Execution 2</th><th style="${th()}">Execution 3</th></tr></thead><tbody><tr><td style="${td("font-weight:700")}">TC1</td><td style="${td("text-align:center;color:#EF4444")}">(1) Failed</td><td style="${td("text-align:center;color:#22C55E")}">(4) Passed</td><td style="${td("text-align:center;color:#22C55E")}">(7) Passed</td></tr><tr><td style="${td("font-weight:700")}">TC2</td><td style="${td("text-align:center;color:#22C55E")}">(2) Passed</td><td style="${td("text-align:center;color:#EF4444")}">(5) Failed</td><td style="${td("text-align:center;color:#22C55E")}">(8) Passed</td></tr><tr><td style="${td("font-weight:700;border-bottom:none")}">TC3</td><td style="${td("text-align:center;color:#EF4444;border-bottom:none")}">(3) Failed</td><td style="${td("text-align:center;color:#EF4444;border-bottom:none")}">(6) Failed</td><td style="${td("text-align:center;color:#22C55E;border-bottom:none")}">(9) Passed</td></tr></tbody></table><p style="color:#A3A3A3;font-size:13px;margin:4px 0">Tests are repeated once all defects from the test run are corrected and a new version is available.</p>`;

const q21Html = `<div><p style="margin:0 0 8px;color:#D4D4D4;font-size:14px">The final grade is assigned based on the final result:</p><div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:12px;font-size:12px"><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">0–50: failed</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">51–60: fair</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">61–70: satisfactory</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">71–80: good</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">81–90: very good</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">91–100: excellent</span></div><table style="${tbl()}"><thead><tr><th style="${thL()}"></th><th style="${th()}">Final result</th><th style="${th()}">Final grade</th></tr></thead><tbody><tr><td style="${td("font-weight:700")}">TC1</td><td style="${td("text-align:center")}">91</td><td style="${td("text-align:center")}">excellent</td></tr><tr><td style="${td("font-weight:700")}">TC2</td><td style="${td("text-align:center")}">50</td><td style="${td("text-align:center")}">failed</td></tr><tr><td style="${td("font-weight:700")}">TC3</td><td style="${td("text-align:center")}">81</td><td style="${td("text-align:center")}">very good</td></tr><tr><td style="${td("font-weight:700")}">TC4</td><td style="${td("text-align:center")}">60</td><td style="${td("text-align:center")}">fair</td></tr><tr><td style="${td("font-weight:700")}">TC5</td><td style="${td("text-align:center")}">70</td><td style="${td("text-align:center")}">satisfactory</td></tr><tr><td style="${td("font-weight:700;border-bottom:none")}">TC6</td><td style="${td("text-align:center;border-bottom:none")}">80</td><td style="${td("text-align:center;border-bottom:none")}">good</td></tr></tbody></table></div>`;

