const qD20Html=`<div><p style="margin:0 0 8px;color:#D4D4D4;font-size:14px">The system calculates discount type based on the difference D = CY − BY:</p><div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:12px;font-size:12px"><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">D &lt; 0: error message</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">0 ≤ D &lt; 18: student discount</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">18 ≤ D &lt; 65: no discount</span><span style="padding:4px 10px;border-radius:6px;background:#1A1A1A;border:1px solid #2A2A2A">D ≥ 65: pensioner discount</span></div><p style="color:#A3A3A3;font-size:13px;margin:4px 0">Existing test cases:</p><div style="font-size:12px;color:#A3A3A3;line-height:1.8;font-family:monospace">• BY=1990, CY=2020 → no discount (D=30)<br/>• BY=2030, CY=2029 → error message (D=−1)</div></div>`;

