const qD29Html=`<div style="background:#141414;border:1px solid #2A2A2A;border-radius:10px;padding:14px 18px;margin:12px 0;font-size:13px;line-height:1.7;color:#A3A3A3"><div style="color:#D4D4D4;font-style:italic;margin-bottom:8px">As a customer, I want to be able to filter search results by price range, so that I can find products within my budget more easily.</div><div style="color:#FACC15;font-weight:600;margin-bottom:4px">Acceptance Criteria:</div><div>1. Filter works for all versions from v3.0 upwards</div><div>2. Filter allows setting min and max price</div><div style="margin-bottom:8px">3. Results update dynamically as price range is adjusted</div><div style="color:#888;font-size:12px">Precondition: Product A costs $100, Product B costs $110</div></div>`;

